Actually I spoke too soon, grabbed a few seconds to test it and it turns out they implement Start-Process by joining instead of passing to an exec, so varargs have to be quoted sadly:

```powershell
function Run-Command {
   [CmdletBinding()]
   param(
       [Parameter(ValueFromRemainingArguments=$true)][string[]] $args
   )
   $flags = @{}
   if ($args.Length -eq 0) {
       Write-Error "No command specified"
       return
   }

   $command = $args[0]

   if ($args.Length -gt 1) {
       # Quote all parameters since argument list is turned into a flat string
       for ($i = 1; $i -lt $args.Length; $i++) {
           $args[$i] = "`"" + $args[$i] + "`""
       }
       # Start-Process won't accept empty args, must be unspecified for noargs
       $flags["ArgumentList"] = $args[1..$args.Length]
   }

   $process = Start-Process $command -PassThru -NoNewWindow @flags
   Wait-Process -InputObject $process

   $result = $process.ExitCode
   if ($result -ne 0) {
       Write-Error "Command failed (exit: $result)"
   }
}
```
